{
  "attention_span": {
    "type": "slider",
    "label": "How focused are you on the task right now? (1-Distracted, 10-Laser Focused)",
    "min": 1,
    "max": 10,
    "default": 5
  },
  "working_memory_load": {
    "type": "number",
    "label": "How many related sub-tasks are you actively holding in your mind? (0-None, 5-Excessive)",
    "min": 0,
    "max": 5,
    "default": 2
  },
  "cognitive_flexibility": {
    "type": "slider",
    "label": "How easily can you shift between different aspects of this task? (1-Rigid, 10-Adaptable)",
    "min": 1,
    "max": 10,
    "default": 5
  },
  "impulse_control": {
    "type": "toggle",
    "label": "Do you feel a strong urge to procrastinate or avoid this task? (Yes/No)"
  },
  "emotional_regulation": {
    "type": "slider",
    "label": "How emotionally charged are you feeling about this task/decision? (1-Calm, 10-Overwhelmed)",
    "min": 1,
    "max": 10,
    "default": 5
  },
  "urgency": {
    "type": "number",
    "label": "On a scale of 1-10 how urgent is this task? (1-Can wait, 10-Critical)",
    "min": 1,
    "max": 10,
    "default": 5
  },
 "complexity": {
    "type": "number",
    "label": "On a scale of 1-10 how complex is this task? (1-Simple, 10-Very complex)",
    "min": 1,
    "max": 10,
    "default": 5
  },
  "logic": "((attention_span * cognitive_flexibility) / (working_memory_load + (impulse_control ? 5 : 1) + emotional_regulation + complexity)) * urgency"
}

